// ============= CLOUD TTS SERVICE WITH FALLBACK CHAIN =============
// Premium neural voices for the JARVIS assistant, all on free tiers.
// Providers are tried in order and skipped when their key is missing,
// they recently failed (cooldown), or the time budget has run out:
//
//   Tier 1: ElevenLabs  — free 10k chars/month.
//   Tier 2: Gemini TTS  — free tier, same key the portfolio uses for chat.
//   Tier 3: Pollinations — free key from https://enter.pollinations.ai.
// Keys come from Firestore config/apiKeys (fields: elevenlabs/gemini/
// pollinations) via keyService — never baked into the bundle.
//
// Callers (Siri.js) fall back to the browser's offline speechSynthesis when
// this module rejects, so the assistant always has a voice — even offline.

// Keys are fetched at runtime from Firestore (config/apiKeys) via keyService —
// never from REACT_APP_* env vars, which CRA would bake into the public bundle.
import { getApiKeys } from "../../utils/keyService";

// ElevenLabs voice. NOTE: "Maya" (4O1sYUnmtThcBoSBrri7) is a community
// library voice — the free plan blocks those via API (needs Starter plan).
// Until then: "Matilda", a premade friendly female voice that works on free.
const ELEVENLABS_VOICE_ID = "XrExE9yKIg1WjnnlVkGX";
const ELEVENLABS_MODEL = "eleven_flash_v2_5"; // cheapest/fastest, 0.5 credits/char

const GEMINI_TTS_MODEL = "gemini-2.5-flash-preview-tts";
const GEMINI_VOICE = "Charon"; // deep, informative prebuilt voice

const POLLINATIONS_VOICE = "onyx";

// After a provider fails, skip it for a while so every utterance doesn't
// pay the failed-request latency again.
const COOLDOWN_MS = 5 * 60 * 1000;
const cooldownUntil = { elevenlabs: 0, gemini: 0, pollinations: 0 };

// Cache synthesized audio per text so repeated phrases (intro, confirmations)
// don't burn quota. Object URLs are revoked on eviction.
const audioCache = new Map();
const CACHE_MAX = 20;

const cacheGet = (key) => {
  const hit = audioCache.get(key);
  if (hit) {
    // Refresh LRU position
    audioCache.delete(key);
    audioCache.set(key, hit);
  }
  return hit;
};

const cachePut = (key, value) => {
  if (audioCache.size >= CACHE_MAX) {
    const oldestKey = audioCache.keys().next().value;
    const oldest = audioCache.get(oldestKey);
    audioCache.delete(oldestKey);
    try {
      URL.revokeObjectURL(oldest.url);
    } catch (e) {
      /* noop */
    }
  }
  audioCache.set(key, value);
};

// ---- Network awareness ----------------------------------------------------
// On 2G / data-saver / offline connections, cloud TTS would add seconds of
// dead air before the assistant speaks. Skip straight to the browser voice.
const isConnectionPoor = () => {
  if (typeof navigator === "undefined") return false;
  if (navigator.onLine === false) return true;
  const conn =
    navigator.connection || navigator.mozConnection || navigator.webkitConnection;
  if (conn) {
    if (conn.saveData) return true;
    const type = conn.effectiveType || "";
    if (type === "slow-2g" || type === "2g") return true;
  }
  return false;
};

// Total time we're willing to spend on cloud synthesis before the caller
// falls back to the instant browser voice. Tighter on mobile / 3G.
const getTimeBudgetMs = (isMobile) => {
  const conn =
    typeof navigator !== "undefined" &&
    (navigator.connection || navigator.mozConnection || navigator.webkitConnection);
  if (conn && conn.effectiveType === "3g") return 5000;
  return isMobile ? 7000 : 9000;
};

const fetchWithTimeout = async (url, options = {}, timeoutMs = 8000) => {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(url, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
};

// Gemini returns raw 16-bit mono PCM (base64). Wrap it in a RIFF/WAV header
// so an <audio> element can play it.
const pcmBase64ToWavBlob = (base64, sampleRate) => {
  const binary = atob(base64);
  const pcmLength = binary.length;
  const buffer = new ArrayBuffer(44 + pcmLength);
  const view = new DataView(buffer);

  const writeString = (offset, str) => {
    for (let i = 0; i < str.length; i++) {
      view.setUint8(offset + i, str.charCodeAt(i));
    }
  };

  const numChannels = 1;
  const bytesPerSample = 2;
  const byteRate = sampleRate * numChannels * bytesPerSample;

  writeString(0, "RIFF");
  view.setUint32(4, 36 + pcmLength, true);
  writeString(8, "WAVE");
  writeString(12, "fmt ");
  view.setUint32(16, 16, true); // fmt chunk size
  view.setUint16(20, 1, true); // PCM
  view.setUint16(22, numChannels, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, byteRate, true);
  view.setUint16(32, numChannels * bytesPerSample, true);
  view.setUint16(34, 16, true); // bits per sample

  writeString(36, "data");
  view.setUint32(40, pcmLength, true);

  const bytes = new Uint8Array(buffer, 44);
  for (let i = 0; i < pcmLength; i++) {
    bytes[i] = binary.charCodeAt(i);
  }

  return new Blob([buffer], { type: "audio/wav" });
};

// ---- Providers ------------------------------------------------------------

const synthesizeWithElevenLabs = async (text, timeoutMs, apiKey) => {
  const response = await fetchWithTimeout(
    `https://api.elevenlabs.io/v1/text-to-speech/${ELEVENLABS_VOICE_ID}?output_format=mp3_22050_32`,
    {
      method: "POST",
      headers: {
        "xi-api-key": apiKey,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ text, model_id: ELEVENLABS_MODEL }),
    },
    timeoutMs
  );

  if (!response.ok) {
    throw new Error(`ElevenLabs HTTP ${response.status}`);
  }

  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

const synthesizeWithGemini = async (text, timeoutMs, apiKey) => {
  const response = await fetchWithTimeout(
    `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_TTS_MODEL}:generateContent?key=${apiKey}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts: [{ text }] }],
        generationConfig: {
          responseModalities: ["AUDIO"],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: GEMINI_VOICE },
            },
          },
        },
      }),
    },
    timeoutMs
  );

  if (!response.ok) {
    // 429 = free-tier quota hit; other errors are equally worth a cooldown
    throw new Error(`Gemini TTS HTTP ${response.status}`);
  }

  const data = await response.json();
  const part = data?.candidates?.[0]?.content?.parts?.find(
    (p) => p.inlineData?.data
  );
  if (!part) {
    throw new Error("Gemini TTS returned no audio");
  }

  const mimeType = part.inlineData.mimeType || "";
  const rateMatch = mimeType.match(/rate=(\d+)/);
  const sampleRate = rateMatch ? parseInt(rateMatch[1], 10) : 24000;

  const blob = pcmBase64ToWavBlob(part.inlineData.data, sampleRate);
  return URL.createObjectURL(blob);
};

const synthesizeWithPollinations = async (text, timeoutMs, apiKey) => {
  // Pollinations does TTS through the OpenAI chat-completions audio pattern;
  // its /v1/audio/speech endpoint rejects "openai-audio" as a text model.
  // Requires pollen balance on the account.
  const response = await fetchWithTimeout(
    "https://gen.pollinations.ai/v1/chat/completions",
    {
      method: "POST",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: "openai-audio",
        modalities: ["text", "audio"],
        audio: { voice: POLLINATIONS_VOICE, format: "mp3" },
        messages: [
          {
            role: "system",
            content:
              "Repeat the user's text exactly as speech. Do not add anything.",
          },
          { role: "user", content: text },
        ],
      }),
    },
    timeoutMs
  );

  if (!response.ok) {
    throw new Error(`Pollinations HTTP ${response.status}`);
  }

  const data = await response.json();
  const b64 = data?.choices?.[0]?.message?.audio?.data;
  if (!b64) {
    throw new Error("Pollinations returned no audio");
  }

  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return URL.createObjectURL(new Blob([bytes], { type: "audio/mpeg" }));
};

const PROVIDERS = [
  { name: "elevenlabs", synthesize: synthesizeWithElevenLabs },
  { name: "gemini", synthesize: synthesizeWithGemini },
  { name: "pollinations", synthesize: synthesizeWithPollinations },
];

/**
 * Synthesize `text` with the first available cloud provider.
 * Resolves { url, provider } where url is a playable object URL.
 * Rejects when every provider fails or is skipped — caller should fall back
 * to the browser's speechSynthesis.
 *
 * The whole attempt respects a time budget (tighter on mobile/3G) so a bad
 * network never leaves the assistant silent for long.
 *
 * Object URLs are owned by this module's cache; do NOT revoke them.
 */
export const synthesizeSpeech = async (text, { isMobile = false } = {}) => {
  const cleanText = (text || "").trim();
  if (!cleanText) {
    throw new Error("No text to synthesize");
  }

  const cached = cacheGet(cleanText);
  if (cached) {
    console.log(`🔊 TTS cache hit (${cached.provider})`);
    return cached;
  }

  if (isConnectionPoor()) {
    throw new Error("Connection too poor for cloud TTS");
  }

  const deadline = Date.now() + getTimeBudgetMs(isMobile);
  const errors = [];
  const apiKeys = await getApiKeys(); // Firestore-backed, cached after first call

  for (const provider of PROVIDERS) {
    if (!apiKeys[provider.name]) {
      continue; // no API key configured for this provider
    }
    if (Date.now() < cooldownUntil[provider.name]) {
      continue;
    }
    const remainingMs = deadline - Date.now();
    if (remainingMs < 1500) {
      errors.push("time budget exhausted");
      break;
    }
    try {
      const url = await provider.synthesize(
        cleanText,
        remainingMs,
        apiKeys[provider.name]
      );
      const result = { url, provider: provider.name };
      cachePut(cleanText, result);
      return result;
    } catch (error) {
      console.warn(`🔊 ${provider.name} TTS failed:`, error.message);
      if (!error.skipCooldown) {
        cooldownUntil[provider.name] = Date.now() + COOLDOWN_MS;
      }
      errors.push(`${provider.name}: ${error.message}`);
    }
  }

  throw new Error(
    `All cloud TTS providers failed (${errors.join("; ") || "no providers configured"})`
  );
};

/**
 * Fire-and-forget cache warmer. Call with known phrases (e.g. the intro)
 * as soon as the assistant opens, so the first spoken line plays instantly.
 */
export const warmUpTts = (text, opts) => {
  synthesizeSpeech(text, opts).catch(() => {
    /* silent — playback path has its own fallback */
  });
};
