// ============= RUNTIME API KEY SERVICE =============
// API keys live in Firestore at config/apiKeys (public read, admin write)
// instead of being baked into the JS bundle by CRA env vars — GitHub push
// protection blocks bundles containing them, and bots scrape leaked keys.
// Fields: { gemini, elevenlabs, pollinations }
//
// Cached in memory + sessionStorage (1h TTL) so each visit costs at most
// one Firestore read.

import { doc, getDoc } from "firebase/firestore";
import { db } from "../firebase/config";

const CACHE_KEY = "runtime_api_keys_v1";
const CACHE_TTL_MS = 60 * 60 * 1000;

let memoryCache = null;
let inflight = null;

const readSessionCache = () => {
  try {
    const raw = sessionStorage.getItem(CACHE_KEY);
    if (!raw) return null;
    const { at, keys } = JSON.parse(raw);
    if (Date.now() - at > CACHE_TTL_MS) return null;
    return keys;
  } catch (e) {
    return null;
  }
};

const writeSessionCache = (keys) => {
  try {
    sessionStorage.setItem(
      CACHE_KEY,
      JSON.stringify({ at: Date.now(), keys })
    );
  } catch (e) {
    /* noop */
  }
};

/**
 * Resolve the runtime API keys. Always resolves (with {} on failure) so
 * callers can just check for the field they need.
 */
export const getApiKeys = async () => {
  if (memoryCache) return memoryCache;

  const cached = readSessionCache();
  if (cached) {
    memoryCache = cached;
    return cached;
  }

  if (!inflight) {
    inflight = getDoc(doc(db, "config", "apiKeys"))
      .then((snap) => {
        const keys = snap.exists() ? snap.data() : {};
        memoryCache = keys;
        writeSessionCache(keys);
        return keys;
      })
      .catch((error) => {
        console.warn("🔑 keyService: failed to fetch keys:", error.message);
        inflight = null; // allow a retry on next call
        return {};
      });
  }
  return inflight;
};
